import math

INVERSE_MAP = {'S': 'SDG', 'SDG': 'S', 'T': 'TDG', 'TDG': 'T'}
SELF_INVERSE = {'H', 'X', 'Y', 'Z', 'CX', 'CNOT', 'SWAP'}

def are_inverses(gate1, gate2, tolerance=1e-10):
    """
    Check if two gates are inverses.

    Args:
        gate1: (name, qubits, params) tuple
        gate2: (name, qubits, params) tuple
        tolerance: Float comparison tolerance
    Returns:
        True if gates are inverses
    """
    name1, qubits1, params1 = gate1
    name2, qubits2, params2 = gate2

    # Must act on same qubits
    if qubits1 != qubits2:
        return False

    # Self-inverse gates
    if name1 in SELF_INVERSE and name1 == name2:
        return params1 == params2

    # Named inverse pairs (S/Sdg, T/Tdg)
    if name1 in INVERSE_MAP:
        if INVERSE_MAP[name1] == name2:
            return True

    # Rotation gates with opposite angles
    rotation_gates = {'RX', 'RY', 'RZ', 'P'}
    if name1 in rotation_gates and name1 == name2:
        if len(params1) == 1 and len(params2) == 1:
            angle_sum = params1[0] + params2[0]
            # Check sum is zero (or 2*pi for periodicity)
            if abs(angle_sum) < tolerance:
                return True
            if abs(abs(angle_sum) - 2 * math.pi) < tolerance:
                return True

    return False

# Test cases
print(are_inverses(('S', (0,), ()), ('SDG', (0,), ())))  # True
print(are_inverses(('RZ', (0,), (0.5,)), ('RZ', (0,), (-0.5,))))  # True
print(are_inverses(('T', (0,), ()), ('T', (0,), ())))  # False

def gates_commute(g1, g2):
    """Check if two gates commute."""
    # Gates on different qubits commute
    if set(g1[1]).isdisjoint(set(g2[1])):
        return True
    return False

def are_inverses_simple(g1, g2):
    """Check if gates are self-inverses of each other."""
    SELF_INVERSE = {'H', 'X', 'Y', 'Z'}
    return (g1[0] in SELF_INVERSE and g1 == g2)

def commutation_cancellation(gates):
    """
    Cancel gates by moving commuting operations.

    Args:
        gates: List of (name, qubits) tuples
    Returns:
        Optimized gate list
    """
    gates = list(gates)  # Make a copy
    changed = True

    while changed:
        changed = False
        i = 0

        while i < len(gates):
            # Look for inverse of gates[i] in later positions
            for j in range(i + 1, len(gates)):
                if are_inverses_simple(gates[i], gates[j]):
                    # Check if all intermediate gates commute with gates[i]
                    can_commute = all(
                        gates_commute(gates[i], gates[k])
                        for k in range(i + 1, j)
                    )

                    if can_commute:
                        # Remove both gates (j first since it's later)
                        gates.pop(j)
                        gates.pop(i)
                        changed = True
                        break

                # Stop if we can't commute past this gate
                if not gates_commute(gates[i], gates[j]):
                    break

            if changed:
                break
            i += 1

    return gates

# Test: X(0)-Y(1)-X(0) should cancel X gates
gates = [('X', (0,)), ('Y', (1,)), ('X', (0,))]
print(commutation_cancellation(gates))  # [('Y', (1,))]
